"use client"

import { useState } from "react"
import { Bell, Search, AlertTriangle, AlertOctagon } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Badge } from "@/components/ui/badge"
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover"
import Link from "next/link"
import { DashboardThemeToggle } from "@/components/providers/dashboard-theme-toggle"
import { ProfileMenu } from "@/components/dashboard/profile-menu"
import { useSearch } from "@/app/providers/search-context"
import { useSupabase } from "@/hooks/useSupabase"

interface DashboardHeaderProps {
  title: string
  subtitle?: string
  searchValue?: string
  onSearchChange?: (value: string) => void
  hideSearch?: boolean
  searchPlaceholder?: string
}

export function DashboardHeader({ title, subtitle, searchValue, onSearchChange, hideSearch, searchPlaceholder }: DashboardHeaderProps) {
  const { searchQuery, setSearchQuery } = useSearch()
  const [alertsOpen, setAlertsOpen] = useState(false)
  const { data: alertsData } = useSupabase<any>("alerts")

  const effectiveSearchValue = searchValue ?? searchQuery
  const handleSearchChange = (value: string) => {
    if (onSearchChange) onSearchChange(value)
    else setSearchQuery(value)
  }

  // Use real alerts from Supabase
  const activeAlerts = alertsData?.filter((a: any) => a.status === 'active') || []
  const criticalCount = activeAlerts.filter((a: any) => a.type === "critical").length

  return (
    <header className="sticky top-0 z-40 flex h-16 items-center justify-between border-b bg-card px-6">
      <div>
        <h1 className="text-xl font-semibold leading-tight">{title}</h1>
        {subtitle && <p className="text-xs text-muted-foreground mt-0.5">{subtitle}</p>}
      </div>

      <div className="flex items-center gap-4">
        {!hideSearch && (
          <div className="relative hidden md:block">
            <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
            <Input
              value={effectiveSearchValue}
              onChange={(e) => handleSearchChange(e.target.value)}
              placeholder={searchPlaceholder || "Search..."}
              className="w-48 lg:w-64 pl-9 h-9"
            />
          </div>
        )}

        <DashboardThemeToggle />

        <Popover open={alertsOpen} onOpenChange={setAlertsOpen}>
          <PopoverTrigger asChild>
            <Button variant="ghost" size="icon" className="relative h-9 w-9">
              <Bell className="h-5 w-5" />
              {activeAlerts.length > 0 && (
                <Badge
                  variant="destructive"
                  className="absolute -top-1 -right-1 flex h-4 w-4 items-center justify-center p-0 text-[10px] font-bold border-2 border-background"
                >
                  {activeAlerts.length}
                </Badge>
              )}
            </Button>
          </PopoverTrigger>

          <PopoverContent className="w-80 p-0 shadow-xl border-border" align="end">
            <div className="border-b p-4 bg-muted/20">
              <h3 className="font-semibold text-sm">Notifications</h3>
              <p className="text-xs text-muted-foreground">Stay updated on inventory events</p>
            </div>

            <div className="max-h-80 overflow-y-auto">
              {activeAlerts.length === 0 ? (
                <div className="p-8 text-center">
                  <Bell className="h-8 w-8 text-muted-foreground/30 mx-auto mb-2" />
                  <p className="text-xs text-muted-foreground italic">No new notifications</p>
                </div>
              ) : (
                activeAlerts.map((alert: any) => {
                  const Icon = alert.type === "critical" ? AlertOctagon : AlertTriangle
                  return (
                    <Link
                      key={alert.id}
                      href="/dashboard/admin/alerts"
                      onClick={() => setAlertsOpen(false)}
                      className="flex items-start gap-3 border-b border-border/50 p-3 last:border-b-0 hover:bg-muted/50 transition-colors"
                    >
                      <div
                        className={`flex h-8 w-8 shrink-0 items-center justify-center rounded-full ${alert.type === "critical"
                            ? "bg-red-100 text-red-600"
                            : "bg-amber-100 text-amber-600"
                          }`}
                      >
                        <Icon className="h-4 w-4" />
                      </div>
                      <div className="min-w-0 flex-1 space-y-0.5">
                        <p className="text-xs font-bold truncate">{alert.medicine}</p>
                        <p className="text-[11px] text-muted-foreground leading-snug line-clamp-2">{alert.message}</p>
                      </div>
                    </Link>
                  )
                })
              )}
            </div>

            <div className="p-3 border-t bg-muted/10">
              <Link href="/dashboard/admin/alerts" onClick={() => setAlertsOpen(false)} className="block">
                <Button variant="ghost" size="sm" className="w-full text-xs text-primary font-semibold">
                  View All Activity
                </Button>
              </Link>
            </div>
          </PopoverContent>
        </Popover>

        <ProfileMenu />
      </div>
    </header>
  )
}