"use client"

import { useState } from "react"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { Brain, Loader2, Zap, AlertTriangle, Clock } from "lucide-react"
import { useSupabase } from "@/hooks/useSupabase"

export function AIInsightsPanel() {
  const [insights, setInsights] = useState<any[]>([])
  const [isGenerating, setIsGenerating] = useState(false)
  const { data: medicines } = useSupabase<any>("medicines")

  const generateInsights = async () => {
    if (!medicines) return
    setIsGenerating(true)

    // Simulate complex AI processing
    await new Promise(resolve => setTimeout(resolve, 1500))

    const newInsights = []

    // 1. Check for critical shortages
    const critical = medicines.filter(m => m.current_stock === 0)
    if (critical.length > 0) {
      newInsights.push({
        text: `Critical shortage of ${critical[0].name} detected. Resource redistribution recommended.`,
        icon: Zap,
        color: "text-red-500",
        bgColor: "bg-red-50 dark:bg-red-950/20"
      })
    }

    // 2. Check for low stock items
    const low = medicines.filter(m => m.current_stock > 0 && m.current_stock <= m.min_threshold)
    if (low.length > 0) {
      newInsights.push({
        text: `${low.length} items are below minimum threshold. Consider initiating reorder queue.`,
        icon: AlertTriangle,
        color: "text-amber-500",
        bgColor: "bg-amber-50 dark:bg-amber-900/10"
      })
    }

    // 3. Check for expiry risks
    const today = new Date()
    const thirtyDays = new Date(today.getTime() + 30 * 24 * 60 * 60 * 1000)
    const expiring = medicines.filter(m => {
      const exp = m.expiry_date ? new Date(m.expiry_date) : null
      return exp && exp <= thirtyDays && exp >= today
    })

    if (expiring.length > 0) {
      newInsights.push({
        text: `${expiring.length} batches expiring within 30 days. Priority usage required.`,
        icon: Clock,
        color: "text-blue-500",
        bgColor: "bg-blue-50 dark:bg-blue-900/10"
      })
    }

    if (newInsights.length === 0) {
      newInsights.push({
        text: "Inventory is healthy. No immediate risks or optimizations identified.",
        icon: Brain,
        color: "text-green-500",
        bgColor: "bg-green-50 dark:bg-green-950/10"
      })
    }

    setInsights(newInsights)
    setIsGenerating(false)
  }

  return (
    <Card className="border-border bg-card">
      <CardHeader className="flex flex-row items-center justify-between">
        <div>
          <CardTitle className="text-lg text-card-foreground flex items-center gap-2">
            <Brain className="h-5 w-5 text-primary" />
            AI Insights
          </CardTitle>
          <CardDescription>Intelligent analysis of live data</CardDescription>
        </div>
        <Button
          onClick={generateInsights}
          disabled={isGenerating || !medicines}
          size="sm"
          variant="outline"
          className="gap-2 h-8"
        >
          {isGenerating ? (
            <Loader2 className="h-3 w-3 animate-spin" />
          ) : (
            <Zap className="h-3 w-3" />
          )}
          {isGenerating ? "Analyzing..." : "Analyze"}
        </Button>
      </CardHeader>
      <CardContent>
        {insights.length > 0 ? (
          <div className="space-y-3">
            {insights.map((insight, index) => (
              <div key={index} className={`flex items-start gap-3 p-3 rounded-lg ${insight.bgColor}`}>
                <div className={`mt-0.5 ${insight.color}`}>
                  <insight.icon className="h-4 w-4" />
                </div>
                <p className="text-sm text-foreground/80 leading-snug">
                  {insight.text}
                </p>
              </div>
            ))}
          </div>
        ) : (
          <div className="text-center py-10">
            <div className="flex h-12 w-12 items-center justify-center rounded-full bg-muted mx-auto mb-4">
              <Brain className="h-6 w-6 text-muted-foreground/30" />
            </div>
            <p className="text-muted-foreground text-sm">
              Current medicine inventory patterns appear stable. Click "Analyze" for a deeper risk assessment.
            </p>
          </div>
        )}
      </CardContent>
    </Card>
  )
}
